mapper.select:
SELECT A.*, B.TOTAL_CNT AS totalCnt
FROM (
    SELECT TT1.*
    FROM (
        SELECT ROWNUM AS RNUM, T1.*
        FROM (
            SELECT *
            FROM TRIP
            WHERE 1=1

                AND (TRIP_NM LIKE '%' || #{searchWord} || '%' OR TRIP_ADDR LIKE '%' || #{searchWord} || '%')


                AND TRIP_CLSF = #{tripClsf}

            ORDER BY TRIP_CONTS_ID DESC
        ) T1  
        WHERE ROWNUM <= #{pageSize} * (#{pageNo} - 1) + #{pageSize}
    ) TT1
    WHERE RNUM >= #{pageSize} * (#{pageNo} - 1) + 1
) A CROSS JOIN (
    SELECT COUNT(*) TOTAL_CNT
    FROM TRIP
    WHERE 1=1

        AND (TRIP_NM LIKE '%' || #{searchWord} || '%' OR TRIP_ADDR LIKE '%' || #{searchWord} || '%')


        AND TRIP_CLSF = #{tripClsf}

) B
